// Contract B ingress: { dlq_id, operator }. n8n wraps a POST body under `.body`.
const root = $input.first().json || {};
const body = root.body || root;
const dlq_id = body.dlq_id || null;
const operator = body.operator || 'unknown';
const uuidRe = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
if (!dlq_id || !uuidRe.test(String(dlq_id))) {
  // Bad request — carry the error forward, the Guard will emit a 400 via the single Respond path.
  return [{ json: { _bad: true, code: 400, message: 'dlq_id missing or not a uuid', dlq_id, operator, correlation_id: null } }];
}
return [{ json: {
  dlq_id,
  operator,
  supabase_url: ($env.SUPABASE_URL || '').replace(/\/$/, ''),
  service_key: $env.SUPABASE_SERVICE_KEY || ''
} }];

// Decide replayability. Emits a single item carrying either a refusal (ok:false + code)
// or a green light (ok:true + everything the dispatch path needs). The IF after this
// routes to exactly one Respond node, so responseMode:responseNode never dangles.
const p = $('Parse Input').first().json || {};

// Registry of replayable source workflows: DLQ.workflow name -> target n8n workflow id.
// G1 stores the failed workflow's NAME, so we key on that. Extend as services 2-11 land.
const REGISTRY = { '03-onboarding': 'a10b0000-0000-4000-8000-000000000003', '06-billing-dunning': 'a10b0000-0000-4000-8000-000000000007' };

function refuse(code, message, correlation_id) {
  return [{ json: { ok: false, code, message, correlation_id: correlation_id || null, operator: p.operator } }];
}

// Bad input short-circuited in Parse Input.
if (p._bad) return refuse(p.code || 400, p.message || 'bad request', null);

const resp = $('Load DLQ Row').first().json || {};
const rows = resp.body;
if (!Array.isArray(rows)) return refuse(500, 'could not read dead_letter_queue', null);
if (rows.length === 0) return refuse(404, 'dlq_id not found', null);

const row = rows[0];
const cid = row.correlation_id || null;

if (row.status === 'manual')   return refuse(409, 'refused: poison / attempt cap reached (status=manual)', cid);
if (row.status === 'resolved') return refuse(409, 'already resolved', cid);
if (row.status === 'replayed') return refuse(409, 'a replay is already in progress', cid);
if (row.status !== 'open')     return refuse(409, 'not replayable in status=' + row.status, cid);

const target = REGISTRY[row.workflow];
if (!target) return refuse(409, 'no replay handler registered for workflow ' + row.workflow, cid);

const payload = row.payload || {};
const trigger = payload.trigger || null;
if (!trigger || typeof trigger !== 'object' || Object.keys(trigger).length === 0) {
  return refuse(409, 'nothing to replay: original trigger payload was not captured', cid);
}
const tenant_id = row.tenant_id || trigger.tenant_id || null;
if (!tenant_id) return refuse(409, 'cannot replay: no tenant_id on the DLQ row or its trigger payload', cid);

return [{ json: {
  ok: true,
  dlq_id: p.dlq_id,
  operator: p.operator,
  target_workflow_id: target,
  workflow_name: row.workflow,
  correlation_id: cid,
  tenant_id,
  trigger,
  attempts: row.attempts,
  supabase_url: p.supabase_url
} }];

const g = $('Guard').first().json;
return [{ json: {
  tenant_id: g.tenant_id,
  correlation_id: g.correlation_id,
  service: 'replay',
  step: 'dispatch',
  status: 'started',
  payload: { dlq_id: g.dlq_id, operator: g.operator, workflow: g.workflow_name, from_attempts: g.attempts }
} }];

// Shape the re-injection payload for the source workflow's Execute Workflow Trigger.
// body = the ORIGINAL trigger; correlation_id preserved; replay:true so the source
// bypasses its idempotency gate and reuses the id.
const g = $('Guard').first().json;
return [{ json: {
  body: g.trigger,
  correlation_id: g.correlation_id,
  tenant_id: g.tenant_id,
  replay: true,
  dlq_id: g.dlq_id
} }];

const g = $('Guard').first().json;
return [{ json: {
  tenant_id: g.tenant_id,
  correlation_id: g.correlation_id,
  service: 'replay',
  step: 'dispatch',
  status: 'success',
  payload: { dlq_id: g.dlq_id, operator: g.operator, workflow: g.workflow_name }
} }];

// Replay failed again. Classify (same lens as G1) and bump the SAME row via the central
// bump_dlq RPC keyed by the ORIGINAL (correlation_id, workflow) -> attempts++ and
// -> manual at the cap. We do this explicitly (not via G1) because 05 CAUGHT the error,
// so the original workflow's name is preserved rather than being recorded as 05-dlq-replay.
const g = $('Guard').first().json;
const errItem = $input.first().json || {};
const err = errItem.error || {};
const msg = String(err.message || errItem.message || 'replay re-failed').slice(0, 500);
const hay = (msg + ' ' + (err.name || '')).toLowerCase();
const poison = ['syntaxerror','typeerror','unexpected token','missing tenant','cannot read prop','is not valid json',' 400',' 401',' 403',' 422','validation','malformed'];
let error_class = 'transient';
if (poison.some(s => hay.includes(s))) error_class = 'poison';
return [{ json: {
  supabase_url: g.supabase_url,
  p_correlation_id: g.correlation_id,
  p_workflow: g.workflow_name,
  p_tenant_id: g.tenant_id,
  p_error: msg,
  p_error_class: error_class,
  p_payload: { trigger: g.trigger, replay: true, operator: g.operator }
} }];

