const g = $('Guard').first().json;
const bumped = $('Bump DLQ (re-fail)').first().json || {};
const arr = bumped.body;
const row = Array.isArray(arr) ? (arr[0] || {}) : (arr || {});
return [{ json: {
  tenant_id: g.tenant_id,
  correlation_id: g.correlation_id,
  service: 'replay',
  step: 'dispatch',
  status: 'error',
  payload: { dlq_id: g.dlq_id, operator: g.operator, workflow: g.workflow_name, attempts: row.attempts != null ? row.attempts : null, new_status: row.status || null }
} }];
